INSERT OR REPLACE INTO intelligence_shards (id, name, sector, content) VALUES ('SUPERPOWERS/research/grok_validation_2026-05-01/references/CLAUDE.md', 'CLAUDE.md', 'SUPERPOWERS/RESEARCH/GROK_VALIDATION_2026-05-01/REFERENCES', 'Skills are organized into bucket folders under `skills/`:

- `engineering/` — daily code work
- `productivity/` — daily non-code workflow tools
- `misc/` — kept around but rarely used
- `personal/` — tied to my own setup, not promoted
- `deprecated/` — no longer used

Every skill in `engineering/`, `productivity/`, or `misc/` must have a reference in the top-level `README.md` and an entry in `.claude-plugin/plugin.json`. Skills in `personal/` and `deprecated/` must not appear in either.

Each skill entry in the top-level `README.md` must link the skill name to its `SKILL.md`.

Each bucket folder has a `README.md` that lists every skill in the bucket with a one-line description, with the skill name linked to its `SKILL.md`.
');
